int findGCD(int a, int b) {
    if (a == 0)
        return b;
    return findGCD(b % a, a);
}

void solve() {
    int n;
    cin>>n;
    vi a(n);
    forit(x, a) cin>>x;
    vi b = a;
    sort(all(b));
    if(b[0] == b[n - 1]) {
        out(b[0]);
